  function renderOptions(rawText) {
    var container = document.getElementById('polarActionsContainer');
    if (!container) return;

    var regex = /(?:^|\n)\s*(?:\*+)?(\d+)[\.\:：]\s*(.*?)\s*丨\s*(.*?)(?:\*+)?(?=\n|$)/g;
    var matches = [];
    var m;
    while ((m = regex.exec(rawText)) !== null) matches.push(m);

    container.innerHTML = '';

    if (matches.length === 0) {
      container.innerHTML = '<div class="empty-state">🌸 花落无声，静待新思 🌸</div>';
      return;
    }

    var romanMap = ['', 'I', 'II', 'III', 'IV', 'V', 'VI', 'VII', 'VIII', 'IX', 'X'];

    for (var i = 0; i < matches.length; i++) {
      var match = matches[i];
      var idx = match[1];
      var category = match[2].trim();
      var desc = match[3].trim();
      var fullContent = category + ' 丨 ' + desc;
      var numIdx = parseInt(idx);
      var romanIdx = (numIdx > 0 && numIdx <= 10) ? romanMap[numIdx] : idx;

      var btn = document.createElement('div');
      btn.className = 'polar-action-btn';
      btn.innerHTML = '<span class="action-idx">' + romanIdx + '.</span><span class="action-text"></span>';
      btn.querySelector('.action-text').textContent = fullContent;

      (function(text) {
        btn.onclick = function() {
          var clean = text.replace(/<[^>]*>?/gm, '');
          var sepIdx = clean.indexOf('丨');
          var finalText = sepIdx !== -1 ? clean.substring(sepIdx + 1).trim() : clean;

          if (typeof window.triggerSlash === 'function') {
            window.triggerSlash('/setinput ' + finalText);
          } else {
            console.log('[可待] 选中:', finalText);
            showToast('✨ 已选: ' + finalText);
          }
        };
      })(fullContent);

      container.appendChild(btn);
    }
  }

  function showToast(msg) {
    var el = document.createElement('div');
    el.textContent = msg;
    el.style.cssText = 'position:fixed;bottom:20px;left:50%;transform:translateX(-50%);background:rgba(255,239,244,.92);color:#d14c77;padding:8px 18px;border-radius:40px;font-size:13px;box-shadow:0 4px 15px rgba(255,145,164,.2);z-index:9999;border:1px solid #ffb7c5;transition:opacity .4s;backdrop-filter:blur(8px);-webkit-backdrop-filter:blur(8px);';
    document.body.appendChild(el);
    setTimeout(function() { el.style.opacity = '0'; setTimeout(function() { el.remove(); }, 400); }, 1400);
  }

  function toggleCollapsible() {
    if (_toggling) return;
    _toggling = true;

    var el = document.getElementById('sakuraCollapsible');
    var header = el.querySelector('.sakura-header');

    if (_closeTimer) {
      clearTimeout(_closeTimer);
      _closeTimer = null;
    }

    if (el.classList.contains('expanded')) {
      /* ===== CLOSE SEQUENCE ===== */
      // Step 1: Add closing — stripes transition to left
      el.classList.add('closing');

      // Step 2: After stripes have mostly exited, remove expanded (triggers grid collapse)
      _closeTimer = setTimeout(function() {
        el.classList.remove('expanded');
        header.setAttribute('aria-expanded', 'false');

        // Step 3: After grid finishes collapsing, clean up closing class
        // Reset stripes to right side (ready for next open)
        setTimeout(function() {
          el.classList.remove('closing');
          _toggling = false;
          updateIframeHeight();
        }, 650);

      }, 420);

      setTimeout(updateIframeHeight, 50);

    } else {
      /* ===== OPEN SEQUENCE ===== */
      // Clean any stale closing state
      el.classList.remove('closing');

      // Force stripes to right-side starting position before expanding
      // (They should already be there, but ensure no stale transform)
      var stripes = el.querySelectorAll('.stripe');
      for (var i = 0; i < stripes.length; i++) {
        stripes[i].style.transition = 'none';
        // Read layout to flush the forced style
        void stripes[i].offsetWidth;
        stripes[i].style.transition = '';
      }

      // Now expand — stripes will transition from right to center
      el.classList.add('expanded');
      header.setAttribute('aria-expanded', 'true');
      triggerPetalFall();

      setTimeout(function() { _toggling = false; updateIframeHeight(); }, 700);
      setTimeout(updateIframeHeight, 50);
    }
  }

  function triggerPetalFall() {
    var cw = document.querySelector('.sakura-content-wrapper');
    if (!cw) return;
    var emojis = ['🌸', '💮', '✨'];

    for (var i = 0; i < 8; i++) {
      var p = document.createElement('div');
      p.className = 'petal-particle';
      p.innerText = emojis[Math.floor(Math.random() * emojis.length)];
      var sz = 10 + Math.random() * 8;
      var sx = 5 + Math.random() * 90;
      var dur = 1.6 + Math.random() * 1.5;
      var del = Math.random() * 0.4;
      p.style.fontSize = sz + 'px';
      p.style.left = sx + '%';
      p.style.animationDuration = dur + 's';
      p.style.animationDelay = del + 's';
      cw.appendChild(p);

      (function(el, parent, t) {
        setTimeout(function() { if (el.parentNode === parent) parent.removeChild(el); }, t);
      })(p, cw, (dur + del) * 1000 + 100);
    }
  }

  function updateIframeHeight() {
    if (window.parent && window.parent !== window) {
      window.parent.postMessage({ type: 'resizeIframe', height: document.body.scrollHeight }, '*');
    }
  }

  document.addEventListener('keydown', function(e) {
    if (e.key === 'Enter' || e.key === ' ') {
      var a = document.activeElement;
      if (a && a.classList.contains('sakura-header')) { e.preventDefault(); toggleCollapsible(); }
    }
