            name: `DeepSeek V4：首条 user 消息末尾（${getPresetModeLabel(m)}）`,
            enabled: true,
            attach_role: 'user',
            attach_index: 1,
            attach_side: 'end',
            content: PRESET_PROMPTS[m] ?? '',
        });
    }

    function createDraftRule(index) {
        return buildDefaultRule(index, {
            id: `rule-${Date.now()}-${index}`,
            name: `附着规则 ${index}`,
            enabled: true,
            attach_role: 'user',
            attach_index: -1,
            attach_side: 'end',
        });
    }

    function normalizeRule(rule, index) {
        if (!isObject(rule)) return null;
        return {
            id: String(rule.id ?? `rule-${index + 1}`).trim() || `rule-${index + 1}`,
            name: String(rule.name ?? '').trim(),
            enabled: rule.enabled !== false,
            content: typeof rule.content === 'string' ? rule.content : '',
            attach_role: normalizeAttachRole(rule.attach_role ?? rule.role ?? 'user'),
            attach_index: normalizeInteger(rule.attach_index ?? rule.index ?? 1, 1),
            attach_side: normalizeSide(rule.attach_side ?? rule.side ?? 'end'),
        };
    }

    function detectPresetMode(rules) {
        const first = Array.isArray(rules) ? rules[0] : null;
        if (!first) return PRESET_MODE.IMMERSIVE;
        const content = normalizeText(first.content).trim();
        if (first.attach_role === 'user' && first.attach_index === 1 && first.attach_side === 'end') {
            if (content === PRESET_PROMPTS[PRESET_MODE.IMMERSIVE]) return PRESET_MODE.IMMERSIVE;
            if (content === PRESET_PROMPTS[PRESET_MODE.ANALYSIS]) return PRESET_MODE.ANALYSIS;
            if (content === PRESET_PROMPTS[PRESET_MODE.FORMAT_ENFORCE]) return PRESET_MODE.FORMAT_ENFORCE;
        }
        return PRESET_MODE.CUSTOM;
    }

    // ========== CONFIG: NORMALIZATION ==========
    function buildDefaultAttachConfig(mode) {
        const m = normalizePresetMode(mode);
        return {
            enabled: true,
            joiner: JOINER,
            preset_mode: m,
            rules: [buildPresetPrimaryRule(m)],
        };
    }

    function normalizeAttachConfig(input) {
        const s = isObject(input) ? input : {};
        const d = buildDefaultAttachConfig();
        const rules = Array.isArray(s.rules)
            ? s.rules.map((r, i) => normalizeRule(r, i)).filter(Boolean)
            : [];
        const presetMode = normalizePresetMode(
            s.preset_mode,
            detectPresetMode(rules.length > 0 ? rules : d.rules),
        );
        return {
            enabled: s.enabled !== false,
            joiner: typeof s.joiner === 'string' && s.joiner.length > 0 ? s.joiner : JOINER,
            preset_mode: presetMode,
            rules: rules.length > 0 ? rules : d.rules,
        };
    }

    function buildDefaultConfig() {
        return {
            enabled: true,
            target_sources: ['deepseek'],
            role_tags: true,
            show_cache_stats: true,
            debug_log: false,
            separate_wi_lights: false,
            keep_tail_assistant: true,
            custom_prefill_enabled: false,
            custom_prefill_content: '',
            attach: buildDefaultAttachConfig(),
        };
    }

    function normalizeConfig(input) {
        const s = isObject(input) ? input : {};
        const d = buildDefaultConfig();
        return {
            enabled: s.enabled !== false,
            target_sources: Array.isArray(s.target_sources) && s.target_sources.length > 0
                ? s.target_sources.map(x => String(x).trim().toLowerCase()).filter(Boolean)
                : d.target_sources,
            role_tags: s.role_tags !== false,
            show_cache_stats: s.show_cache_stats !== false,
            debug_log: s.debug_log === true,
            separate_wi_lights: s.separate_wi_lights === true,
            keep_tail_assistant: s.keep_tail_assistant !== false,
            custom_prefill_enabled: s.custom_prefill_enabled === true,
            custom_prefill_content: typeof s.custom_prefill_content === 'string' ? s.custom_prefill_content : '',
            attach: normalizeAttachConfig(s.attach),
        };
    }

    function cloneConfig(c) {
        return JSON.parse(JSON.stringify(isObject(c) ? c : buildDefaultConfig()));
    }

    function applyPresetMode(config, mode, opts) {
        const next = cloneConfig(config);
        const m = normalizePresetMode(mode);
        const resetExtra = isObject(opts) && opts.resetExtraRules === true;
        const rest = resetExtra ? [] : (Array.isArray(next.attach?.rules) ? next.attach.rules.slice(1) : []);
        if (!isObject(next.attach)) next.attach = {};
        next.attach.preset_mode = m;
        if (m === PRESET_MODE.CUSTOM) return normalizeConfig(next);
        next.attach.rules = [buildPresetPrimaryRule(m), ...rest];
        if (typeof next.attach.joiner !== 'string' || !next.attach.joiner) next.attach.joiner = JOINER;
        return normalizeConfig(next);
    }

    // ========== CONFIG: STORAGE ==========
    const STORAGE_OPT = { type: 'extension', extension_id: CONFIG_KEY };

    function getScriptVars() {
        const v = getVariables(STORAGE_OPT);
        return isObject(v) ? v : {};
    }

    function getConfig() {
        const vars = getScriptVars();
        const raw = vars[CONFIG_KEY];
        let config = normalizeConfig(raw);
        const oldAttach = vars[OLD_ATTACH_CONFIG_KEY];
        if (isObject(oldAttach) && !(isObject(raw) && isObject(raw.attach))) {
            config.attach = normalizeAttachConfig(oldAttach);
        }
        return config;
    }

    function saveConfig(config) {
        updateVariablesWith((vars) => {
            const next = isObject(vars) ? { ...vars } : {};
            next[CONFIG_KEY] = normalizeConfig(config);
            delete next[OLD_ATTACH_CONFIG_KEY];
            return next;
        }, STORAGE_OPT);
        return getConfig();
    }

    function migrateFromScriptVars() {
        try {
            const oldVars = getVariables({ type: 'script' });
            if (isObject(oldVars) && isObject(oldVars[CONFIG_KEY])) {
                const currentVars = getScriptVars();
                if (!isObject(currentVars[CONFIG_KEY])) {
                    saveConfig(normalizeConfig(oldVars[CONFIG_KEY]));
                    console.log(LOG_TAG, 'Migrated config from script vars to extension storage');
                }
            }
        } catch (e) { console.log(LOG_TAG, 'Migration check skipped:', e.message); }
    }

    function ensureConfig() {
        migrateFromScriptVars();
        return saveConfig(getConfig());
    }

    // ========== WI LIGHTS SEPARATION ==========
    function handleWorldInfoActivated(entries) {
        if (!Array.isArray(entries)) return;
        const config = getConfig();
        if (!config.enabled || !config.separate_wi_lights) return;

        const greenFingerprints = [];
        for (const entry of entries) {
            if (!isObject(entry)) continue;
            if (entry.constant) continue;
            const content = String(entry.content ?? '').trim();
            if (!content) continue;
            greenFingerprints.push(content);
        }

        globalThis[WI_CAPTURE_KEY] = {
            greenFingerprints,
            timestamp: Date.now(),
        };

        if (config.debug_log && greenFingerprints.length > 0) {
            console.log(LOG_TAG, 'WI lights captured:', greenFingerprints.length, 'green entries');
        }
    }

    function separateWILights(chat, config) {
        const capture = globalThis[WI_CAPTURE_KEY];
        globalThis[WI_CAPTURE_KEY] = null;

        if (!capture || !Array.isArray(capture.greenFingerprints) || capture.greenFingerprints.length === 0) return null;
        if (Date.now() - capture.timestamp > 15000) return null;

        var firstUserIdx = -1;
        for (var i = 0; i < chat.length; i++) {
            if (normalizeRole(chat[i].role) === 'user') { firstUserIdx = i; break; }
        }
        if (firstUserIdx <= 0) return null;

        var originalOrder = capture.greenFingerprints;
        var sorted = originalOrder.slice().sort(function(a, b) { return b.length - a.length; });
        var removedSet = {};

        for (var i = 0; i < firstUserIdx; i++) {
            var msg = chat[i];
            if (!isObject(msg)) continue;
            var text = extractText(msg.content);
            if (!text) continue;

            var modified = false;
            for (var fi = 0; fi < sorted.length; fi++) {
                var fp = sorted[fi];
                if (removedSet[fp]) continue;
                if (text.indexOf(fp) >= 0) {
                    text = text.replace(fp, '');
                    removedSet[fp] = true;
                    modified = true;
                    if (config.debug_log) {
                        console.log(LOG_TAG, 'WI green removed from preHistory:', fp.substring(0, 60) + '...');
                    }
                }
            }

            if (modified) {
                text = text.replace(/\n{3,}/g, '\n\n').replace(/^\n+|\n+$/g, '').trim();
                if (typeof msg.content === 'string') {
                    msg.content = text;
                } else if (Array.isArray(msg.content)) {
                    for (var pi = 0; pi < msg.content.length; pi++) {
                        if (isObject(msg.content[pi]) && msg.content[pi].type === 'text') {
                            msg.content[pi] = { type: 'text', text: text };
                            break;
                        }
                    }
                }
            }
        }

        for (var i = firstUserIdx - 1; i >= 0; i--) {
            var text = extractText(chat[i].content).trim();
            if (!text) chat.splice(i, 1);
        }

        var removedContents = [];
        for (var oi = 0; oi < originalOrder.length; oi++) {
            if (removedSet[originalOrder[oi]]) {
                removedContents.push(originalOrder[oi]);
            }
        }

        if (config.debug_log && removedContents.length > 0) {
            console.log(LOG_TAG, 'WI separation result:', removedContents.length, 'green entries moved to bottom (original order preserved)');
        }

        return removedContents.length > 0 ? removedContents : null;
    }

    // ========== ATTACH ENGINE ==========
    function buildRawChatHistorySnapshot() {
        const lastMessageId = Number(getLastMessageId());
        if (!Number.isInteger(lastMessageId) || lastMessageId < 0) return [];
        const chatMessages = getChatMessages(`0-${lastMessageId}`, { hide_state: 'unhidden' });
        const snapshot = [];
        const ignoreSymbol = SillyTavern?.symbols?.ignore;
        const settings = isObject(SillyTavern?.chatCompletionSettings) ? SillyTavern.chatCompletionSettings : {};
        const namesBehavior = Number(settings.names_behavior ?? 0);
        const userName = String(SillyTavern?.name1 ?? '');
        const hasGroup = Boolean(SillyTavern?.groupId);

        for (const msg of chatMessages) {
            if (!isObject(msg)) continue;
            const extra = isObject(msg.extra) ? msg.extra : {};
            if (ignoreSymbol && extra[ignoreSymbol]) continue;
            const role = normalizeAttachRole(msg.role);
            const name = String(msg.name ?? '');
            let content = normalizeText(msg.message);

            if (namesBehavior === 0) {
                const shouldPrefix =
                    (hasGroup && name.length > 0 && name !== userName) ||
                    (Boolean(extra.force_avatar) && name.length > 0 && name !== userName && role !== 'system');
                if (shouldPrefix) content = `${name}: ${content}`;
            } else if (namesBehavior === 2 && role !== 'system' && name.length > 0) {
                content = `${name}: ${content}`;
            }

            const invocations = Array.isArray(extra.tool_invocations) ? extra.tool_invocations.slice() : [];
            const prev = snapshot[snapshot.length - 1];
            if (extra.isSmallSys === true && invocations.length > 0 && prev?.role === 'assistant') {
                prev.invocations = Array.isArray(prev.invocations)
                    ? prev.invocations.concat(invocations)
                    : invocations;
                continue;
            }

            snapshot.push({
                message_id: normalizeInteger(msg.message_id, snapshot.length),
                role, content, name, invocations,
            });
        }
        return snapshot;
    }

    function matchesRawHistoryMessage(raw, outgoing) {
        if (!isObject(outgoing)) return false;
        const outRole = normalizeAttachRole(outgoing.role);
        if (outRole !== raw.role) return false;
        if (raw.name && typeof outgoing.name === 'string' && outgoing.name && outgoing.name !== raw.name) return false;
        const rawText = normalizeText(raw.content);
        const outText = extractTextFromOutgoingContent(outgoing.content);
        if (outText === rawText) return true;
        if (rawText.length > 0 && outText.endsWith(rawText)) return true;
        return false;
    }

    function mapRawHistoryToOutgoingChat(chat, rawHistory) {
        const mapping = new Map();
        let oi = chat.length - 1;
        for (let ri = rawHistory.length - 1; ri >= 0 && oi >= 0; ri--) {
            for (; oi >= 0; oi--) {
                if (matchesRawHistoryMessage(rawHistory[ri], chat[oi])) {
                    mapping.set(ri, oi);
                    oi--;
                    break;
                }
            }
        }
        return mapping;
    }

    function resolveTargetRawMessage(rawHistory, rule) {
        const matches = [];
        for (let i = 0; i < rawHistory.length; i++) {
            if (rawHistory[i].role === rule.attach_role) {
                matches.push({ rawIndex: i, message: rawHistory[i] });
            }
        }
        if (matches.length === 0) return null;
        const ni = rule.attach_index === 0 ? 1 : rule.attach_index;
        const ti = ni > 0 ? ni - 1 : matches.length + ni;
        if (ti < 0 || ti >= matches.length) return null;
        return matches[ti];
    }

    function applyAttachRules(chat, attachConfig) {
        if (!attachConfig.enabled) return;
        const rules = attachConfig.rules.filter(
            r => r.enabled && String(r.content ?? '').trim().length > 0,
        );
        if (rules.length === 0) return;

        const rawHistory = buildRawChatHistorySnapshot();
        if (rawHistory.length === 0) return;

        const mapping = mapRawHistoryToOutgoingChat(chat, rawHistory);
        for (const rule of rules) {
            const target = resolveTargetRawMessage(rawHistory, rule);
            if (!target) continue;
            const oi = mapping.get(target.rawIndex);
            if (!Number.isInteger(oi)) continue;
            const msg = chat[oi];
            if (!isObject(msg)) continue;
            const next = attachToContent(msg.content, rule.content, rule.attach_side, attachConfig.joiner);
            if (next !== msg.content) msg.content = next;
        }
    }

    // ========== RESTRUCTURE ENGINE ==========
    function isToolRelated(msg) {
        return normalizeRole(msg.role) === 'tool' || Boolean(msg.tool_calls) || Boolean(msg.tool_call_id);
    }

    function groupEntries(entries) {
        var groups = [];
        for (var i = 0; i < entries.length; i++) {
            var e = entries[i];
            var last = groups.length > 0 ? groups[groups.length - 1] : null;
            if (last && last.role === e.role) {
                last.texts.push(e.text);
            } else {
                groups.push({ role: e.role, texts: [e.text] });
            }
        }
        return groups;
    }

    function buildSections(groups, config) {
        var sections = [];
        for (var i = 0; i < groups.length; i++) {
            var g = groups[i];
            var content = g.texts.join(JOINER);
            if (config.role_tags) {
                sections.push('<role==' + g.role + '>\n' + content + '\n</role==' + g.role + '>');
            } else {
                sections.push(content);
            }
        }
        return sections;
    }

    function restructureMessages(chat, config, greenContents) {
        if (!Array.isArray(chat) || chat.length === 0) return;

        var firstUserIdx = -1;
        for (var i = 0; i < chat.length; i++) {
            if (normalizeRole(chat[i].role) === 'user') { firstUserIdx = i; break; }
        }
        if (firstUserIdx < 0) {
            if (config.debug_log) console.log(LOG_TAG, 'No user message found, skipping');
            return;
        }

        var preHistory = chat.slice(0, firstUserIdx);
        var afterFirstUser = chat.slice(firstUserIdx);

        var lastConvIdx = 0;
        for (var i = afterFirstUser.length - 1; i >= 0; i--) {
            if (normalizeRole(afterFirstUser[i].role) === 'user' || isToolRelated(afterFirstUser[i])) {
                lastConvIdx = i;
                break;
            }
        }

        var chatHistory = afterFirstUser.slice(0, lastConvIdx + 1);
        var postHistoryMessages = afterFirstUser.slice(lastConvIdx + 1);

        if (config.debug_log) {
            console.log(LOG_TAG, 'Partition:', {
                preHistory: preHistory.length,
                chatHistory: chatHistory.length,
                postHistory: postHistoryMessages.length,
            });
        }

        var preEntries = [];
        for (var i = 0; i < preHistory.length; i++) {
            var role = normalizeRole(preHistory[i].role);
            var text = extractText(preHistory[i].content).trim();
            if (text) preEntries.push({ role: role, text: text });
        }

        var postHistoryEntries = [];
        var tailAssistantMessages = [];
        for (var i = 0; i < postHistoryMessages.length; i++) {
            var role = normalizeRole(postHistoryMessages[i].role);
            var text = extractText(postHistoryMessages[i].content).trim();
            if (!text) continue;
            if (role === 'assistant' && config.keep_tail_assistant) {
                tailAssistantMessages.push({ role: 'assistant', content: text });
            } else {
                postHistoryEntries.push({ role: role, text: text });
            }
        }

        var firstUserContent = chatHistory[0] ? chatHistory[0].content : undefined;
        var firstUserText = extractText(firstUserContent).trim();

        var isSingleMessage = (chatHistory.length <= 1);
        var newMessages = [];

        if (isSingleMessage) {
            var singleGreenEntries = [];
            if (Array.isArray(greenContents) && greenContents.length > 0) {
                for (var gi = 0; gi < greenContents.length; gi++) {
                    singleGreenEntries.push({ role: 'system', text: greenContents[gi] });
                }
            }
            var allEntries = preEntries.concat(singleGreenEntries).concat(postHistoryEntries);
            var allSections = buildSections(groupEntries(allEntries), config);
            if (firstUserText) allSections.push(firstUserText);
            var mergedText = allSections.join(JOINER);
            var mergedContent = buildMergedContent(mergedText, firstUserContent);
            newMessages.push({ role: 'user', content: mergedContent });

            for (var ti = 0; ti < tailAssistantMessages.length; ti++) {
                newMessages.push(tailAssistantMessages[ti]);
            }
            if (config.custom_prefill_enabled && config.custom_prefill_content.trim()) {
                newMessages.push({ role: 'assistant', content: config.custom_prefill_content.trim() });
            }
        } else {
            // TOP ZONE (cached prefix): preHistory + first user input
            var preSections = buildSections(groupEntries(preEntries), config);
            if (firstUserText) preSections.push(firstUserText);
            var mergedText = preSections.join(JOINER);
            var mergedContent = buildMergedContent(mergedText, firstUserContent);
            newMessages.push({ role: 'user', content: mergedContent });

            // MIDDLE ZONE: chat history (extract inline system messages)
            var extractedSystems = [];
            for (var i = 1; i < chatHistory.length; i++) {
                var msg = chatHistory[i];
                var role = normalizeRole(msg.role);
                if (role === 'system') {
                    var text = extractText(msg.content).trim();
                    if (text) extractedSystems.push({ role: 'system', text: text });
                    continue;
                }
                if (isToolRelated(msg)) {
                    newMessages.push(msg);
                    continue;
                }
                var newMsg = Object.assign({}, msg);
                if (msg.role === 'model') newMsg.role = 'assistant';
                newMessages.push(newMsg);
            }

            // BOTTOM ZONE (high attention, D1-equivalent): prepend to last user message
            var greenEntries = [];
            if (Array.isArray(greenContents) && greenContents.length > 0) {
                for (var gi = 0; gi < greenContents.length; gi++) {
                    greenEntries.push({ role: 'system', text: greenContents[gi] });
                }
            }
            var postEntries = greenEntries.concat(extractedSystems).concat(postHistoryEntries);
            if (postEntries.length > 0) {
                var postSections = buildSections(groupEntries(postEntries), config);
                var postText = postSections.join(JOINER);

                var lastUserIdx = -1;
                for (var i = newMessages.length - 1; i >= 0; i--) {
                    if (normalizeRole(newMessages[i].role) === 'user') { lastUserIdx = i; break; }
                }

                if (lastUserIdx >= 0) {
                    var lastUser = newMessages[lastUserIdx];
                    if (typeof lastUser.content === 'string') {
                        lastUser.content = postText + JOINER + lastUser.content;
                    } else if (Array.isArray(lastUser.content)) {
                        var textParts = lastUser.content.filter(function(p) { return isObject(p) && p.type === 'text'; });
                        var mediaParts = lastUser.content.filter(function(p) { return isObject(p) && p.type !== 'text'; });
                        var existingText = textParts.map(function(p) { return String(p.text || ''); }).join(JOINER);
                        lastUser.content = [{ type: 'text', text: postText + JOINER + existingText }].concat(mediaParts);
                    }
                }
            }

            for (var ti = 0; ti < tailAssistantMessages.length; ti++) {
                newMessages.push(tailAssistantMessages[ti]);
            }
            if (config.custom_prefill_enabled && config.custom_prefill_content.trim()) {
                newMessages.push({ role: 'assistant', content: config.custom_prefill_content.trim() });
            }
        }

        if (config.debug_log) {
            console.log(LOG_TAG, 'BEFORE (' + chat.length + ' messages):');
            chat.forEach(function(m, i) { console.log('  [' + i + '] ' + m.role + ': ' + extractText(m.content).substring(0, 80)); });
            console.log(LOG_TAG, 'AFTER (' + newMessages.length + ' messages):');
            newMessages.forEach(function(m, i) { console.log('  [' + i + '] ' + m.role + ': ' + extractText(m.content).substring(0, 80)); });
        }

        chat.splice(0, chat.length, ...newMessages);
    }

    // ========== PIPELINE ==========
    function handlePromptReady(eventData) {
        if (!isObject(eventData) || eventData.dryRun || !Array.isArray(eventData.chat)) return;

        try {
            const config = getConfig();
            if (!config.enabled) return;

            const settings = SillyTavern?.chatCompletionSettings;
            const source = isObject(settings)
                ? String(settings.chat_completion_source ?? '').trim().toLowerCase()
                : '';

            if (!source || !config.target_sources.includes(source)) {
                if (config.debug_log) console.log(LOG_TAG, 'Skipping: source "' + source + '" not in targets');
                return;
            }

            // Step 1: attach content to original messages (before restructure)
            applyAttachRules(eventData.chat, config.attach);

            // Step 1.5: separate WI green lights from preHistory to bottom
            var greenContents = null;
            if (config.separate_wi_lights) {
                greenContents = separateWILights(eventData.chat, config);
            }

            // Step 2: restructure messages for cache optimization
            restructureMessages(eventData.chat, config, greenContents);
        } catch (error) {
            console.error(LOG_TAG, error);
            notify('error', '缓存优化脚本执行失败: ' + String(error.message ?? error));
        }
    }

    // ========== CACHE STATS ==========
    function showCacheStats(usage) {
        if (!isObject(usage)) return;
        var hit = Number(usage.prompt_cache_hit_tokens) || 0;
        var miss = Number(usage.prompt_cache_miss_tokens) || 0;
        var total = Number(usage.prompt_tokens) || (hit + miss);
        var comp = Number(usage.completion_tokens) || 0;
        var rate = total > 0 ? ((hit / total) * 100).toFixed(1) : '0.0';
        var msg = '缓存命中: ' + hit + ' tok (' + rate + '%) | 未命中: ' + miss + ' tok | prompt: ' + total + ' | 生成: ' + comp;
        console.log(LOG_TAG, 'Cache stats:', usage);
        notify('info', msg);
    }

    function installFetchInterceptor() {
        if (globalThis[FETCH_KEY]) {
            try { window.fetch = globalThis[FETCH_KEY]; } catch {}
        }

        var originalFetch = window.fetch;
        globalThis[FETCH_KEY] = originalFetch;

        window.fetch = async function() {
            var args = arguments;
            var response = await originalFetch.apply(this, args);

            try {
                var config = getConfig();
                if (!config.enabled || !config.show_cache_stats) return response;

                var url = typeof args[0] === 'string' ? args[0] : (args[0] && args[0].url ? args[0].url : '');
                if (!url || url.indexOf('/api/backends/chat-completions/generate') < 0) return response;

                var contentType = response.headers.get('content-type') || '';
                var isStream = contentType.indexOf('text/event-stream') >= 0;

                if (isStream && response.body) {
                    var buffer = '';
                    var lastUsage = null;
                    var decoder = new TextDecoder();
                    var transform = new TransformStream({
                        transform: function(chunk, controller) {
                            controller.enqueue(chunk);
                            buffer += decoder.decode(chunk, { stream: true });
                            var lines = buffer.split('\n');
                            buffer = lines.pop();
                            for (var li = 0; li < lines.length; li++) {
                                var line = lines[li];
                                if (line.indexOf('data: ') === 0 && line.indexOf('[DONE]') < 0) {
                                    try {
                                        var parsed = JSON.parse(line.substring(6));
                                        if (parsed && parsed.usage) lastUsage = parsed.usage;
                                    } catch (e) {}
                                }
                            }
                        },
                        flush: function() {
                            if (lastUsage) showCacheStats(lastUsage);
                        },
                    });

                    var newBody = response.body.pipeThrough(transform);
                    return new Response(newBody, {
                        status: response.status,
                        statusText: response.statusText,
                        headers: response.headers,
                    });
                } else if (!isStream) {
                    var clone = response.clone();
                    clone.json().then(function(data) {
                        if (data && data.usage) showCacheStats(data.usage);
                    }).catch(function() {});
                }
            } catch (e) {
                console.warn(LOG_TAG, 'Fetch interceptor error:', e);
            }

            return response;
        };

        return {
            stop: function() {
                if (globalThis[FETCH_KEY]) {
                    try { window.fetch = globalThis[FETCH_KEY]; } catch {}
                    delete globalThis[FETCH_KEY];
                }
            },
        };
    }

