    function buildConfigEditor(initialConfig) {
        let wc = normalizeConfig(cloneConfig(initialConfig));
        let container = null;
        let listenersBound = false;

        function syncPresetMode() {
            wc.attach.preset_mode = detectPresetMode(wc.attach.rules);
        }

        function ensureRules() {
            if (!Array.isArray(wc.attach.rules) || wc.attach.rules.length === 0) {
                wc.attach.rules = [createDraftRule(1)];
            }
        }

        function getMarkup() {
            ensureRules();
            syncPresetMode();
            return buildEditorMarkup(wc);
        }

        function render() {
            if (isDomElement(container)) container.innerHTML = getMarkup();
        }

        function handleChange(event) {
            const t = event.target;
            if (!isDomElement(t)) return;
            const tag = getTagName(t);
            if (!['input', 'textarea', 'select'].includes(tag)) return;
            const f = t.dataset?.field;
            if (!f) return;
            const ri = t.dataset?.ruleIndex;

            switch (f) {
                case 'enabled': wc.enabled = Boolean(t.checked); break;
                case 'role_tags': wc.role_tags = Boolean(t.checked); break;
                case 'show_cache_stats': wc.show_cache_stats = Boolean(t.checked); break;
                case 'debug_log': wc.debug_log = Boolean(t.checked); break;
                case 'separate_wi_lights': wc.separate_wi_lights = Boolean(t.checked); break;
                case 'keep_tail_assistant': wc.keep_tail_assistant = Boolean(t.checked); break;
                case 'custom_prefill_enabled': wc.custom_prefill_enabled = Boolean(t.checked); break;
                case 'custom_prefill_content': wc.custom_prefill_content = String(t.value ?? ''); break;
                case 'target_sources':
                    wc.target_sources = String(t.value ?? '').split(',').map(s => s.trim().toLowerCase()).filter(Boolean);
                    break;
                case 'attach_enabled': wc.attach.enabled = Boolean(t.checked); break;
                case 'attach_preset_mode': {
                    const mode = normalizePresetMode(t.value, PRESET_MODE.CUSTOM);
                    if (mode === PRESET_MODE.CUSTOM) {
                        wc.attach.preset_mode = PRESET_MODE.CUSTOM;
                    } else {
                        wc = applyPresetMode(wc, mode, { resetExtraRules: false });
                        render();
                    }
                    break;
                }
                case 'attach_joiner': wc.attach.joiner = String(t.value ?? ''); break;
                default:
                    if (ri !== undefined && ri !== null) {
                        const idx = Number(ri);
                        const rule = wc.attach.rules[idx];
                        if (!rule) break;
                        switch (f) {
                            case 'rule_enabled': rule.enabled = Boolean(t.checked); break;
                            case 'rule_name': rule.name = String(t.value ?? ''); break;
                            case 'rule_attach_role': rule.attach_role = normalizeAttachRole(t.value); break;
                            case 'rule_attach_index': rule.attach_index = normalizeInteger(t.value, 1); break;
                            case 'rule_attach_side': rule.attach_side = normalizeSide(t.value); break;
                            case 'rule_content': rule.content = String(t.value ?? ''); break;
                        }
                        if (idx === 0) syncPresetMode();
                    }
            }
        }

        function handleAction(event) {
            const raw = event.target;
            if (!isDomElement(raw) || typeof raw.closest !== 'function') return;
            const el = raw.closest('[data-action]');
            if (!isDomElement(el)) return;
            event.preventDefault();
            const action = el.dataset.action;

            if (action === 'preset-immersive') {
                wc = applyPresetMode(wc, PRESET_MODE.IMMERSIVE, { resetExtraRules: false });
                render();
                return;
            }
            if (action === 'preset-analysis') {
                wc = applyPresetMode(wc, PRESET_MODE.ANALYSIS, { resetExtraRules: false });
                render();
                return;
            }
            if (action === 'preset-format-enforce') {
                wc = applyPresetMode(wc, PRESET_MODE.FORMAT_ENFORCE, { resetExtraRules: false });
                render();
                return;
            }
            if (action === 'add-rule') {
                wc.attach.preset_mode = PRESET_MODE.CUSTOM;
                wc.attach.rules.push(createDraftRule(wc.attach.rules.length + 1));
                render();
                return;
            }
            if (action === 'reset-default') {
                const mode = wc.attach.preset_mode === PRESET_MODE.ANALYSIS
                    ? PRESET_MODE.ANALYSIS
                    : PRESET_MODE.IMMERSIVE;
                wc.attach = buildDefaultAttachConfig(mode);
                render();
                return;
            }
            if (action === 'delete-rule') {
                const idx = Number(el.dataset.ruleIndex ?? NaN);
                if (!Number.isInteger(idx)) return;
                wc.attach.rules.splice(idx, 1);
                if (wc.attach.rules.length === 0) {
                    wc.attach = buildDefaultAttachConfig(
                        wc.attach.preset_mode === PRESET_MODE.ANALYSIS
                            ? PRESET_MODE.ANALYSIS
                            : PRESET_MODE.IMMERSIVE,
                    );
                } else {
                    syncPresetMode();
                }
                render();
            }
        }

        function mount(nextContainer) {
            container = isDomElement(nextContainer) ? nextContainer : null;
            if (!isDomElement(container)) return;
            if (!listenersBound) {
                container.addEventListener('input', handleChange);
                container.addEventListener('change', handleChange);
                container.addEventListener('click', handleAction);
                listenersBound = true;
            }
            render();
        }

        return {
            getHtml: () => getMarkup(),
            mount,
            getConfig: () => normalizeConfig(cloneConfig(wc)),
        };
    }

    async function openConfigEditor() {
        const editor = buildConfigEditor(getConfig());
        const result = await SillyTavern.callGenericPopup(
            editor.getHtml(),
            SillyTavern.POPUP_TYPE.TEXT,
            '',
            {
                large: true,
                wide: true,
                wider: true,
                leftAlign: true,
                allowVerticalScrolling: true,
                okButton: '保存',
                cancelButton: '取消',
                onOpen: async (popup) => { editor.mount(popup.content); },
            },
        );
        if (!isAffirmative(result)) return;
        const saved = saveConfig(editor.getConfig());
        updateInfo(saved);
        notify('success', '设置已保存');
    }

    function toggleEnabled() {
        const c = getConfig();
        c.enabled = !c.enabled;
        const saved = saveConfig(c);
        updateInfo(saved);
        notify('success', saved.enabled ? '缓存优化已启用' : '缓存优化已停用');
    }

    function cycleAttachMode() {
        const c = getConfig();
        const modes = [PRESET_MODE.IMMERSIVE, PRESET_MODE.ANALYSIS, PRESET_MODE.FORMAT_ENFORCE, PRESET_MODE.CUSTOM];
        if (!c.attach.enabled) {
            c.attach.enabled = true;
            const next = applyPresetMode(c, PRESET_MODE.IMMERSIVE);
            const saved = saveConfig(next);
            updateInfo(saved);
            notify('success', '附着已启用 → 沉浸式');
            return;
        }
        const currentIdx = modes.indexOf(c.attach.preset_mode);
        const nextIdx = (currentIdx + 1) % (modes.length + 1);
        if (nextIdx >= modes.length) {
            c.attach.enabled = false;
            const saved = saveConfig(c);
            updateInfo(saved);
            notify('success', '附着已关闭');
        } else {
            const next = applyPresetMode(c, modes[nextIdx]);
            const saved = saveConfig(next);
            updateInfo(saved);
            notify('success', '附着模式 → ' + getPresetModeLabel(modes[nextIdx]));
        }
    }

    // ========== INIT ==========
    function init() {
        const config = ensureConfig();
        appendInexistentScriptButtons([
            { name: EDIT_BUTTON_NAME, visible: true },
            { name: TOGGLE_BUTTON_NAME, visible: true },
            { name: ATTACH_MODE_BUTTON_NAME, visible: true },
        ]);
        updateInfo(config);

        pushStop(eventOn(getButtonEvent(EDIT_BUTTON_NAME), () => { void openConfigEditor(); }));
        pushStop(eventOn(getButtonEvent(TOGGLE_BUTTON_NAME), toggleEnabled));
        pushStop(eventOn(getButtonEvent(ATTACH_MODE_BUTTON_NAME), cycleAttachMode));
        pushStop(eventMakeFirst(tavern_events.CHAT_COMPLETION_PROMPT_READY, handlePromptReady));
        pushStop(eventOn(tavern_events.WORLD_INFO_ACTIVATED, handleWorldInfoActivated));

        var fetchInterceptor = installFetchInterceptor();
        if (fetchInterceptor) pushStop(fetchInterceptor);

        const oldAttachRuntime = globalThis['__attachExistingMessageHelperRuntime'];
        if (oldAttachRuntime) {
            if (Array.isArray(oldAttachRuntime.stops)) {
                for (const stop of oldAttachRuntime.stops) {
                    try { stop(); } catch {}
                }
                oldAttachRuntime.stops.length = 0;
            }
            notify('warning', '已自动停用旧版「附着到已有消息」脚本。附着功能已集成到本脚本中。');
        }
    }

    init();
})();

