        try {
            const dbConfig = await getFromDB('config', STORAGE_KEY);
            if (dbConfig && dbConfig.value) savedConfig = { ...savedConfig, ...dbConfig.value };
        } catch (e) { }
    }

    async function saveConfig(overrides = {}) {
        savedConfig = { ...savedConfig, ...overrides };
        await saveToDB('config', { key: STORAGE_KEY, value: savedConfig });
    }

    // ==================== 边界钳位 ====================
    function clampPanelToViewport(panel) {
        if (!panel || panel.style.display !== 'flex') return;
        const rect = panel.getBoundingClientRect();
        const winW = topWindow.innerWidth;
        const winH = topWindow.innerHeight;
        let newLeft = rect.left, newTop = rect.top;
        const margin = 10;
        if (rect.right > winW - margin) newLeft = winW - rect.width - margin;
        if (rect.left < margin) newLeft = margin;
        if (rect.bottom > winH - margin) newTop = winH - rect.height - margin;
        if (rect.top < margin) newTop = margin;
        if (newLeft !== rect.left) panel.style.left = newLeft + 'px';
        if (newTop !== rect.top) panel.style.top = newTop + 'px';
        saveConfig({ panelLeft: panel.style.left, panelTop: panel.style.top });
    }

    function clampBubbleToViewport(bubble) {
        if (!bubble) return;
        const rect = bubble.getBoundingClientRect();
        const winW = topWindow.innerWidth;
        const winH = topWindow.innerHeight;
        let newLeft = rect.left, newTop = rect.top;
        const margin = 8;
        if (rect.right > winW - margin) newLeft = winW - rect.width - margin;
        if (rect.left < margin) newLeft = margin;
        if (rect.bottom > winH - margin) newTop = winH - rect.height - margin;
        if (rect.top < margin) newTop = margin;
        if (newLeft !== rect.left) bubble.style.left = newLeft + 'px';
        if (newTop !== rect.top) bubble.style.top = newTop + 'px';
        const side = (newLeft + rect.width / 2) < winW / 2 ? 'left' : 'right';
        if (side === 'left') bubble.style.right = 'auto';
        else bubble.style.left = 'auto';
        saveConfig({ bubbleTop: bubble.style.top, bubbleSide: side });
    }

